    def search(self, index_name: str, query: dict, size: int = 10, from_: int = 0, sort: list = None) -> dict:
        """Execute a search query."""
        full_index_name = f"{self.index_prefix}-{index_name}"
        body = {"query": query, "size": size, "from": from_}
        if sort:
            body["sort"] = sort

        response = self.es.search(index=full_index_name, body=body)
        hits = response["hits"]
        results = {
            "total": hits["total"]["value"] if isinstance(hits["total"], dict) else hits["total"],
            "max_score": hits["max_score"],
            "hits": [
                {
                    "id": hit["_id"],
                    "score": hit["_score"],
                    "source": hit["_source"],
                }
                for hit in hits["hits"]
            ],
        }
        logger.info(f"Search in '{full_index_name}' returned {results['total']} results")
