    def search_logs(
        self,
        query_text: str = None,
        level: str = None,
        service: str = None,
        environment: str = None,
        time_range_minutes: int = 60,
        size: int = 50,
        index_name: str = "logs",
    ) -> dict:
        """Search logs with multiple filters."""
        now = datetime.utcnow()
        gte = (now - timedelta(minutes=time_range_minutes)).isoformat()

        must_clauses = []
        filter_clauses = [{"range": {"@timestamp": {"gte": gte, "lte": now.isoformat()}}}]

        if query_text:
            must_clauses.append({"match": {"message": {"query": query_text, "fuzziness": "AUTO"}}})
        if level:
            filter_clauses.append({"term": {"level": level.upper()}})
        if service:
            filter_clauses.append({"term": {"service": service}})
        if environment:
            filter_clauses.append({"term": {"environment": environment}})

