class ElasticsearchLogHandler(logging.Handler):
    """Python logging handler that sends log records to Elasticsearch."""

    def __init__(self, platform: ElasticsearchPlatform, service: str = "default", environment: str = "development", host: str = "localhost"):
        super().__init__()
        self.platform = platform
        self.service = service
        self.environment = environment
        self.host = host

    def emit(self, record: logging.LogRecord):
        try:
            exception = None
            if record.exc_info and record.exc_info[1]:
                import traceback

                exception = {
                    "type": type(record.exc_info[1]).__name__,
                    "message": str(record.exc_info[1]),
                    "stacktrace": "".join(traceback.format_exception(*record.exc_info)),
                }

            self.platform.log(
                level=record.levelname,
                message=self.format(record),
                service=self.service,
                host=self.host,
                environment=self.environment,
                exception=exception,
                metadata={"logger_name": record.name, "module": record.module, "funcName": record.funcName, "lineno": record.lineno},
            )
        except Exception:
            self.handleError(record)


