def setup_content_index(platform: ElasticsearchPlatform, index_name: str = "content") -> dict:
    """Create a content index for full-text search of documents/articles."""
    mappings = {
        "properties": {
            "@timestamp": {"type": "date"},
            "title": {"type": "text", "analyzer": "standard", "fields": {"keyword": {"type": "keyword"}}},
            "body": {"type": "text", "analyzer": "standard"},
            "author": {"type": "keyword"},
            "tags": {"type": "keyword"},
            "category": {"type": "keyword"},
            "status": {"type": "keyword"},
            "url": {"type": "keyword"},
            "views": {"type": "integer"},
            "created_at": {"type": "date"},
            "updated_at": {"type": "date"},
        }
    }
    settings = {
        "number_of_shards": 1,
        "number_of_replicas": 0,
        "analysis": {
            "analyzer": {
                "content_analyzer": {
                    "type": "custom",
                    "tokenizer": "standard",
                    "filter": ["lowercase", "stop", "snowball"],
                }
            }
        },
    }
    return platform.create_index(index_name, mappings=mappings, settings=settings)


